class EventEmitter {
  #subscribers = new Map();

  subscribe(event, listener) {
    if (!this.#subscribers.has(event)) {
      this.#subscribers.set(event, new Set());
    }
    this.#subscribers.get(event).add(listener);
    return () => this.unsubscribe(event, listener); // returns unsubscribe fn
  }

  unsubscribe(event, listener) {
    this.#subscribers.get(event)?.delete(listener);
  }

  emit(event, data) {
    this.#subscribers.get(event)?.forEach(listener => listener(data));
  }
}

// Subject
class Store extends EventEmitter {
  #stock = {};

  addProduct(name, quantity) {
    this.#stock[name] = (this.#stock[name] ?? 0) + quantity;
    this.emit('product:added', { name, quantity });
  }
}

// Usage
const store = new Store();

const unsubscribe = store.subscribe('product:added', ({ name, quantity }) => {
  console.log(`New stock: ${quantity}x ${name}`);
});

store.addProduct('iPhone', 50); // New stock: 50x iPhone
unsubscribe();                   // Stop listening

