type Listener<T = unknown> = (data: T) => void;

class EventEmitter {
  private subscribers = new Map<string, Set<Listener>>();

  subscribe<T>(event: string, listener: Listener<T>): () => void {
    if (!this.subscribers.has(event)) {
      this.subscribers.set(event, new Set());
    }
    this.subscribers.get(event)!.add(listener as Listener);
    return () => this.unsubscribe(event, listener as Listener);
  }

  unsubscribe(event: string, listener: Listener): void {
    this.subscribers.get(event)?.delete(listener);
  }

  emit<T>(event: string, data: T): void {
    this.subscribers.get(event)?.forEach(listener => listener(data));
  }
}

interface ProductEvent { name: string; quantity: number; }

class Store extends EventEmitter {
  private stock: Record<string, number> = {};

  addProduct(name: string, quantity: number): void {
    this.stock[name] = (this.stock[name] ?? 0) + quantity;
    this.emit<ProductEvent>('product:added', { name, quantity });
  }
}

