import java.util.*;
import java.util.function.Consumer;

class EventEmitter {
    private final Map<String, List<Consumer<Object>>> subscribers = new HashMap<>();

    public Runnable subscribe(String event, Consumer<Object> listener) {
        subscribers.computeIfAbsent(event, k -> new ArrayList<>()).add(listener);
        return () -> {
            List<Consumer<Object>> list = subscribers.get(event);
            if (list != null) list.remove(listener);
        };
    }

    public void emit(String event, Object data) {
        List<Consumer<Object>> list = subscribers.getOrDefault(event, List.of());
        new ArrayList<>(list).forEach(l -> l.accept(data));
    }
}

class Store extends EventEmitter {
    private final Map<String, Integer> stock = new HashMap<>();

    public void addProduct(String name, int quantity) {
        stock.merge(name, quantity, Integer::sum);
        emit("product:added", Map.of("name", name, "quantity", quantity));
    }
}

// Usage
Store store = new Store();

Runnable unsubscribe = store.subscribe("product:added", data -> {
    Map<?, ?> d = (Map<?, ?>) data;
    System.out.printf("New stock: %sx %s%n", d.get("quantity"), d.get("name"));
});

store.addProduct("iPhone", 50); // New stock: 50x iPhone
unsubscribe.run();               // Stop listening

