class EventEmitter
{
    private readonly Dictionary<string, List<Action<object?>>> _subs = new();

    public Action Subscribe(string @event, Action<object?> listener)
    {
        if (!_subs.ContainsKey(@event)) _subs[@event] = new();
        _subs[@event].Add(listener);
        return () => _subs[@event].Remove(listener);
    }

    public void Emit(string @event, object? data = null)
    {
        if (_subs.TryGetValue(@event, out var list))
            new List<Action<object?>>(list).ForEach(l => l(data));
    }
}

class Store : EventEmitter
{
    private readonly Dictionary<string, int> _stock = new();

    public void AddProduct(string name, int quantity)
    {
        _stock[name] = _stock.GetValueOrDefault(name) + quantity;
        Emit("product:added", new { name, quantity });
    }
}

// Usage
var store = new Store();

var unsubscribe = store.Subscribe("product:added", data =>
{
    dynamic d = data!;
    Console.WriteLine($"New stock: {d.quantity}x {d.name}");
});

store.AddProduct("iPhone", 50); // New stock: 50x iPhone
unsubscribe();                  // Stop listening

