from __future__ import annotations
from collections import defaultdict
from typing import Callable, Any

class EventEmitter:
    def __init__(self):
        self._subscribers: dict[str, list[Callable]] = defaultdict(list)

    def subscribe(self, event: str, listener: Callable) -> Callable:
        self._subscribers[event].append(listener)
        def unsubscribe():
            self._subscribers[event].remove(listener)
        return unsubscribe

    def emit(self, event: str, data: Any = None) -> None:
        for listener in list(self._subscribers[event]):
            listener(data)


class Store(EventEmitter):
    def __init__(self):
        super().__init__()
        self._stock: dict[str, int] = {}

    def add_product(self, name: str, quantity: int) -> None:
        self._stock[name] = self._stock.get(name, 0) + quantity
        self.emit('product:added', {'name': name, 'quantity': quantity})


# Usage
store = Store()
unsubscribe = store.subscribe(
    'product:added',
    lambda e: print(f"New stock: {e['quantity']}x {e['name']}")
)

store.add_product('iPhone', 50)  # New stock: 50x iPhone
unsubscribe()                     # Stop listening
